```class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        for (int i = 1; i <= n / 2; ++i) {
            if (n % i == 0) {
                string subtext = text.substr(0, i);
                bool ok = true;
                for (int j = 0; j < n / i; ++j) {
                    if (j * i < n / 2 && text.substr(j * i, i) != subtext) ok = false;
                    if (j * i >= n / 2 && text.substr(n - (j + 1) * i, i) != subtext) ok = false;
                }
                if (ok) return n / i;
            }
        }
        return 1;
    }
};
